var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，她說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"요란스러운 게 취향이라는 건 알고 있었어. 이 정도일 줄은 예상 못했지만.","JPN":"大袈裟なのが好みだとは知っていた。だが、ここまでとは思わなかったな。","ENG":"I knew you were into all this fancy nonsense. I just didn't realize it was THIS bad.","TWN":"我知道你喜歡找自己麻煩，只是沒想到這麼嚴重。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"계약서는 어디 있지? 빨리 끝내고 싶은데.","JPN":"契約書はどこだ？さっさと済ませたいのだが。","ENG":"So where's the contract? I want to get this over with.","TWN":"契約書在哪？我想快點結束。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"음? 별말 않고 넘어가서 의외인가?","JPN":"うん？何も言わないのが意外だと？","ENG":"Huh? You surprised I just went along with it?","TWN":"嗯？我沒有提出異議，讓你很意外？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"모든 관계는 일방적이지 않아. 서로가 서로한테 빚을 지고 살아가는 셈이지.","JPN":"すべての関係は一方的なものじゃない。お互い借りを作りながら生きてるんだ。","ENG":"Not all relationships are unilateral. Everyone owes something to someone else.","TWN":"所有的關係都不是單方面的。彼此都互相欠著對方的債。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"너에겐 당연한 이야기겠지만, 나는 그걸 너무 늦게 깨달았어.","JPN":"社長にとっては当然の話かもしれないが、私はそれに気づくのが遅すぎた。","ENG":"It might sound obvious to you, but it took me too long for me to realize that.","TWN":"對你來說也許是理所當然的，但我還是太晚才意識到這一點。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"무뎌졌는지도 모르지. 빼앗지 않으면 빼앗기는 데 너무 익숙하니까.","JPN":"鈍くなったのかもしれない。奪わなければ、奪われることに慣れすぎてしまった。","ENG":"Maybe I grew desensitized over the years. I became too used to taking things from others before they take from me.","TWN":"可能是我變得遲鈍了。因為如果我不去爭取，就會被別人直接搶走，這樣的情形我早就司空見慣了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그래서야. 여기는 숨 고를 틈은 주더군.","JPN":"だからなんだ。ここは息抜きする時間ぐらいは与えてくれた。","ENG":"That's why I signed on. You guys let me catch my breath, at least.","TWN":"所以啊，這裡會給人喘息的機會。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"내 삶은 허깨비처럼 잊혀지겠지만...... 여기서라면 뭔가 남길 여지가 있을지도 모르겠어.","JPN":"私の人生は幻影のように忘れられていくのだろうが……ここでなら何か残せるかもしれない。","ENG":"Although my old life will be forgotten like a daydream… Maybe I can leave something here.","TWN":"雖然我的生活會像幻影一樣被遺忘……但這裡也許能夠留下什麼也不一定。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"뭐, 이런 낯부끄러운 소리를 할 수 있는 상대란 것만으로도 너와는 손 잡을 가치가 있겠군.","JPN":"まぁ、こんな恥ずかしいことが言える相手というだけで、社長と手を組む価値はあるだろう。","ENG":"I guess the fact I can say cheesy crap like this to you means you're worth partnering up with.","TWN":"啊，能讓我說出這種難為情的話，那代表很值得與你合作了。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"뒷이야기는 한 잔 하면서 천천히 하지.","JPN":"続きは一杯しながらゆっくり話そう。","ENG":"We can talk more over a drink later.","TWN":"後面的事情，我們邊喝邊聊吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};